const { pregunta, lead_tipo } = $input.first().json;

const segmentosMap = {
  KIDS: ['KIDS', 'GENERAL'],
  ADOLESCENTE: ['KIDS', 'ADULTOS', 'GENERAL'],
  ADULTO: ['ADULTOS', 'GENERAL'],
  AU_PAIR: ['AU_PAIR', 'GENERAL'],
  GENERAL: ['GENERAL']
};

const segmentos = segmentosMap[lead_tipo] || segmentosMap['GENERAL'];

return [{
  json: {
    pregunta: pregunta || 'información general',
    lead_tipo: lead_tipo || 'GENERAL',
    segmentos
  }
}];

const { segmentos } = $input.first().json;
const segmentosStr = segmentos.map(s => `'${s}'`).join(',');

const query = `SELECT id, categoria, segmento, titulo, contenido, activo FROM conocimiento_academia WHERE segmento IN (${segmentosStr}) AND activo = true ORDER BY categoria, segmento, titulo LIMIT 20`;

return [{ json: { query, type: 'conocimiento' } }];

const items = $input.all();
const normData = $('Mapear Segmentos').first().json;

let conocimientoContexto = '';
let configContexto = '';

items.forEach(item => {
  const data = item.json;

  if (data.type === 'conocimiento') {
    if (data.id) {
      conocimientoContexto += `**${data.categoria}**\n${data.titulo}\n${data.contenido}\n\n`;
    }
  } else if (data.type === 'config') {
    configContexto += `${data.key}: ${data.value}\n`;
  }
});

let contextoTotal = '';

if (conocimientoContexto.trim()) {
  contextoTotal += 'INFORMACIÓN SOBRE CLASES:\n' + conocimientoContexto;
}

if (configContexto.trim()) {
  contextoTotal += '\nINFORMACIÓN DE CONTACTO Y CONFIGURACIÓN:\n' + configContexto;
}

const tieneContenido = contextoTotal.trim().length > 0;

return [{
  json: {
    contexto_encontrado: tieneContenido,
    contexto: tieneContenido ? contextoTotal.trim() : 'Sin información disponible.',
    pregunta: normData.pregunta,
    lead_tipo: normData.lead_tipo
  }
}];

const synth = $input.first().json;
const procData = $('Procesar Contextos').first().json;

let respuesta = 'Esa información todavía no la tengo. Voy a consultarlo con la profe Fla y te paso la info.';
if (synth?.choices?.[0]?.message?.content) {
  respuesta = synth.choices[0].message.content.trim();
}

return [{
  json: {
    resultado: respuesta,
    confianza: procData.contexto_encontrado ? 'ALTA' : 'BAJA'
  }
}];
